const AWS = require('aws-sdk');
const crypto = require('crypto');

const dynamo = new AWS.DynamoDB.DocumentClient();

const USERS_TABLE = process.env.USERS_TABLE;
const EMAIL_INDEX_NAME = process.env.EMAIL_INDEX_NAME || 'email-index';

function response(statusCode, body) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Headers': 'Content-Type,Authorization',
      'Access-Control-Allow-Methods': 'OPTIONS,POST'
    },
    body: JSON.stringify(body)
  };
}

function parseBody(event) {
  if (!event || !event.body) return {};
  if (event.isBase64Encoded) {
    const decoded = Buffer.from(event.body, 'base64').toString('utf8');
    return JSON.parse(decoded);
  }
  return JSON.parse(event.body);
}

function normalizeEmail(email) {
  return String(email || '').trim().toLowerCase();
}

function isValidEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function isValidPassword(password) {
  return typeof password === 'string' && password.length >= 8;
}

function hashPassword(password, salt = crypto.randomBytes(16).toString('hex')) {
  const iterations = 310000;
  const keylen = 32;
  const digest = 'sha256';
  const hash = crypto.pbkdf2Sync(password, salt, iterations, keylen, digest).toString('hex');
  return { salt, hash, iterations, digest };
}

function makeUserId() {
  return crypto.randomUUID ? crypto.randomUUID() : crypto.randomBytes(16).toString('hex');
}

exports.handler = async (event) => {
  try {
    if (event.httpMethod === 'OPTIONS') {
      return response(200, { ok: true });
    }

    if (event.httpMethod !== 'POST') {
      return response(405, { message: 'Method Not Allowed' });
    }

    if (!USERS_TABLE) {
      return response(500, { message: 'Server misconfigured' });
    }

    let body;
    try {
      body = parseBody(event);
    } catch (e) {
      return response(400, { message: 'Invalid JSON body' });
    }

    const email = normalizeEmail(body.email);
    const password = body.password;

    if (!email || !isValidEmail(email)) {
      return response(400, { message: 'Valid email is required' });
    }

    if (!isValidPassword(password)) {
      return response(400, { message: 'Password must be at least 8 characters' });
    }

    const existing = await dynamo.query({
      TableName: USERS_TABLE,
      IndexName: EMAIL_INDEX_NAME,
      KeyConditionExpression: '#email = :email',
      ExpressionAttributeNames: {
        '#email': 'email'
      },
      ExpressionAttributeValues: {
        ':email': email
      },
      Limit: 1
    }).promise();

    if (existing.Items && existing.Items.length > 0) {
      return response(409, { message: 'Account already exists' });
    }

    const userId = makeUserId();
    const passwordData = hashPassword(password);
    const now = new Date().toISOString();

    const item = {
      userId,
      email,
      passwordHash: passwordData.hash,
      passwordSalt: passwordData.salt,
      passwordIterations: passwordData.iterations,
      passwordDigest: passwordData.digest,
      status: 'active',
      createdAt: now,
      updatedAt: now
    };

    await dynamo.put({
      TableName: USERS_TABLE,
      Item: item,
      ConditionExpression: 'attribute_not_exists(userId) AND attribute_not_exists(email)'
    }).promise();

    return response(201, {
      userId,
      email,
      createdAt: now
    });
  } catch (err) {
    if (err && err.code === 'ConditionalCheckFailedException') {
      return response(409, { message: 'Account already exists' });
    }

    console.error('Registration error:', err);
    return response(500, { message: 'Internal Server Error' });
  }
};